import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.{HttpRequest, HttpResponse}
import akka.stream.ActorMaterializer

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system = ActorSystem("webhook-proxy")
    implicit val materializer = ActorMaterializer()

    val route = concat(
      path("api" / "v1" / "urls" / Segment) { url =>
        post { request =>
          val userUrl = url.toString
          Http().singleRequest(HttpRequest(uri = userUrl)) map { response =>
            complete(response)
          } recoverWith { case e: Throwable =>
            println(s"Error fetching content from $userUrl")
            complete("Error fetching content")
          }
        }
      }
    )
  }
}